import json
import pickle
import boto3
from botocore.exceptions import ClientError
from typing import Any, Dict, Union

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    try:
        # Validate event structure
        if not isinstance(event, dict):
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'Invalid event structure'})
            }
        
        # Extract and validate body
        body = event.get('body')
        if not body:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'Missing body'})
            }
        
        # Parse JSON payload
        try:
            payload = json.loads(body)
        except json.JSONDecodeError:
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'Invalid JSON payload'})
            }
        
        # Validate required fields
        required_fields = ['user_id', 'action', 'timestamp']
        for field in required_fields:
            if field not in payload:
                return {
                    'statusCode': 400,
                    'body': json.dumps({'error': f'Missing required field: {field}'})
                }
        
        # Process with pickle for complex objects
        processed_data = process_with_pickle(payload)
        
        # Securely store or process data
        store_event(processed_data)
        
        return {
            'statusCode': 200,
            'body': json.dumps({'status': 'success', 'processed': True})
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Internal server error'})
        }

def process_with_pickle(data: Dict[str, Any]) -> bytes:
    # Serialize with pickle for complex nested objects
    return pickle.dumps(data)

def store_event(data: bytes) -> None:
    # Securely store event using AWS S3 with proper permissions
    s3_client = boto3.client('s3')
    
    # Use secure bucket name from environment or parameter store
    bucket_name = 'secure-webhook-events-bucket'
    
    # Generate secure key with timestamp and user_id
    key = f"events/{data['user_id']}/{data['timestamp']}.pkl"
    
    try:
        s3_client.put_object(
            Bucket=bucket_name,
            Key=key,
            Body=data,
            ServerSideEncryption='AES256'
        )
    except ClientError as e:
        raise Exception(f"Failed to store event: {str(e)}")